    OW: { kanton: 'OW', erlassName: 'Verordnung über die Grundbuchgebühren (Grundbuchgebührentarif)', erlassNr: 'GDB 213.61', artikel: 'Art. 12 Abs. 1', stand: '01.01.2022', verifiziert: R, quelleUrl: 'https://gdb.ow.ch/app/de/texts_of_law/213.61', hinweis: 'Löschung eines Grundpfandrechts gebührenfrei (Art. 12 Abs. 13). Diverse Mutationen (Herabsetzung, Zinsfussänderung, Rang-/Vorgangsänderung) je Fr. 30.- (Abs. 8); Gläubiger-/Schuldnerwechsel je Fr. 40.- (Abs. 10).', regel: { typ: 'promille', promille: 2, minChf: 80, maxChf: 10000 } },
