    ZG: { kanton: 'ZG', erlassName: 'Gesetz über den Gebührentarif im Grundbuchwesen (Grundbuchgebührentarif)', erlassNr: 'BGS 215.35', artikel: '§13, §14 lit. e Grundbuchgebührentarif (BGS 215.35)', stand: '1.1.2019', verifiziert: R, quelleUrl: 'https://bgs.zg.ch/app/de/texts_of_law/215.35', hinweis: 'Faktor 3 auf Zeitgebühr, Deckel Fr. 4\'500.-. Pfandgläubiger/-schuldner-Kostentragung nach §4. Pfandrechte zur Wohnbauförderung sind nach §5 von der Gebühr befreit.', regel: { typ: 'formel_extern', hinweis: 'Eintragung/Errichtung oder Erhöhung eines Grundpfands (Schuldbrief/Grundpfandverschreibung): Zeitaufwand nach §13 (Fr. 180.-/Stunde je angebrochene Viertelstunde), multipliziert mit Faktor 3 (§14 lit.' } },
