    BL: { kanton: 'BL', erlassName: 'Verordnung über die Gebühren zum Zivilrecht (GebV)', erlassNr: 'SGS 211.71', artikel: '§ 16 Ziff. 4 Bst. a GebV (SGS 211.71)', stand: '01.01.2013', verifiziert: R, quelleUrl: 'https://bl.clex.ch/app/de/texts_of_law/211.71', hinweis: 'Beurkundung Pfandvertrag in Einzelurkunde ist Notariatsgebühr §14 Z5 a CHF 388.80 (separat).', regel: { typ: 'fix', chf: 300 } },
    SH: { kanton: 'SH', erlassName: 'Grundbuchgebührenverordnung', erlassNr: 'SHR 211.433', artikel: '§ 15 Ziff. 1 (Eintragungsgebühr Grundpfandrechte, Errichtung/Erhöhung)', stand: '1. Januar 2011', verifiziert: R, quelleUrl: 'https://rechtsbuch.sh.ch/app/de/texts_of_law/211.433', hinweis: 'Pfandvermehrung, Pfandentlassung, Tenor-/Rang-/Vorgangsänderung, Nachrückungsrecht, Löschung/Teillöschung, Gläubigervormerk: Fr. 20.-- bis 50.-- (§ 15 Ziff. 2, fix-Rahmen). Leere Pfandstelle/vorbehaltener Vorgang Fr. 50.-- (Ziff. 4). Verlegung auf Stockwerk-/M', regel: { typ: 'promille', promille: 2, minChf: 50 } },
