    AI: { kanton: 'AI', erlassName: 'Gebührentarif (GebT)', erlassNr: 'GS 172.513', artikel: 'Art. 11 Abs. 1 Ziff. 6.1 und 6.2 GebT (GS 172.513)', stand: '01.01.2026', verifiziert: R, quelleUrl: 'https://ai.clex.ch/app/de/texts_of_law/172.513', hinweis: 'Nicht öffentlich beurkundet: 2‰, min. CHF 100, max. CHF 4\'000 (Ziff. 6.2).', regel: { typ: 'promille', promille: 1, minChf: 50, maxChf: 2000 } },
