    GE: { kanton: 'GE', erlassName: 'Règlement sur le tarif des émoluments de l\'office du registre foncier et de la direction de l\'information du territoire (REmORFDIT)', erlassNr: 'RSG E 1 50.06', artikel: 'Art. 4 REmORFDIT', stand: 'Dernières modifications au 24 avril 2024', verifiziert: R, quelleUrl: 'https://silgeneve.ch/legis/data/rsg_e1_50p06.htm', regel: { typ: 'promille', promille: 0.85, maxChf: 20000 } },
    JU: { kanton: 'JU', erlassName: 'Décret fixant les émoluments du registre foncier', erlassNr: 'RSJU 176.331', artikel: 'Art. 7 (Chapitre II)', stand: '24.3.2010', verifiziert: R, quelleUrl: 'https://rsju.jura.ch/fr/viewdocument.html?idn=20021&id=37773&download=1', hinweis: 'Änderung von Pfand/Forderung (Erhöhung, Entlastung, Rangänderung, Nachgang, Titel-Aktualisierung etc.) pauschal 20 Punkte = CHF 21.- (Art. 8 ch. 4 b), unabhängig von der Zahl der Grundstücke. Kumulation gemäss Art. 3.', regel: { typ: 'promille', promille: 1, minChf: 42, maxChf: 10500 } },
