    SZ: { kanton: 'SZ', erlassName: 'Gebührentarif für Notare und Grundbuchverwalter sowie freiberufliche Urkundspersonen', erlassNr: 'SRSZ 213.512', artikel: '§ 5 Abs. 1 Nr. 1 (Begründung dinglicher/persönlicher Rechte) bzw. Nr. 5', stand: '1.2.2021', verifiziert: R, quelleUrl: 'https://www.sz.ch/public/upload/assets/7361/213_512.pdf', hinweis: 'Bei beziffertem (kapitalisiertem) Wert wertabhängig nach Nr. 1; ohne Wert nur fix Fr. 8.-- (Nr. 5). Zuordnung der Dienstbarkeit zu \'persönliche/dingliche Rechte\' nach Nr. 1 ist sachlich naheliegend, aber im Tarif nicht namentlich genannt.', regel: { typ: 'promille', promille: 0.9, maxChf: 13500 } },
    OW: { kanton: 'OW', erlassName: 'Verordnung über die Grundbuchgebühren (Grundbuchgebührentarif)', erlassNr: 'GDB 213.61', artikel: 'Art. 10 Abs. 1-5', stand: '01.01.2022', verifiziert: R, quelleUrl: 'https://gdb.ow.ch/app/de/texts_of_law/213.61', hinweis: 'Dienstbarkeiten als Fixgebühr (nicht wertabhängig); nur die Grundlast ist wertabhängig (2 ‰, min Fr. 80.-). Löschung kostenlos.', regel: { typ: 'fix', chf: 80 } },
    NW: { kanton: 'NW', erlassName: 'Verordnung zum Gesetz über die amtlichen Kosten (Gebührenverordnung, GebV) vom 20. Februar 2024, Anhang Gebührentarif Ziff. 2.6 (Grundbuchgesetzgebung, NG 214.1)', erlassNr: 'NG 265.51', artikel: 'GebV NG 265.51, Anhang Tarif-Nr. 2.6.2.1 (Grunddienstbarkeit/Personaldienstbarkeit); 2.6.2.2 (Grundlast)', stand: '1. Januar 2025', verifiziert: R, quelleUrl: 'https://gesetze.nw.ch/app/de/texts_of_law/265.51', hinweis: 'Dienstbarkeit fix Fr. 50.-; Grundlast hingegen 2 Promille des Realwertes (Min. Fr. 200.-). Loeschung einer Dienstbarkeit Fr. 30.- (Tarif-Nr. 2.6.6.2).', regel: { typ: 'fix', chf: 50 } },
    GL: { kanton: 'GL', erlassName: 'Verordnung über die Gebühren im Zivilrecht (Gebührentarif ZGB, GebT ZGB)', erlassNr: 'GS III B/7/1', artikel: 'Art. 13 Abs. 3 Bst. a GebT ZGB', stand: '09.02.2022', verifiziert: R, quelleUrl: 'https://gesetze.gl.ch/app/de/texts_of_law/III%20B%2F7%2F1', hinweis: 'Pauschal, kein kapitalisierter Wert; +5 Fr. je weiteres Grundbuchblatt.', regel: { typ: 'fix', chf: 50 } },
    ZG: { kanton: 'ZG', erlassName: 'Gesetz über den Gebührentarif im Grundbuchwesen (Grundbuchgebührentarif)', erlassNr: 'BGS 215.35', artikel: '§13, §14 lit. g Grundbuchgebührentarif (BGS 215.35)', stand: '1.1.2019', verifiziert: R, quelleUrl: 'https://bgs.zg.ch/app/de/texts_of_law/215.35', hinweis: 'Faktor 2 auf Zeitgebühr, Deckel Fr. 3\'000.-. Kein kapitalisierter Wert als Bemessungsgrundlage - reine Aufwandbemessung.', regel: { typ: 'formel_extern', hinweis: 'Eintragung einer Dienstbarkeit oder Grundlast (z.B. Grunddienstbarkeit, Nutzniessung, Wohnrecht): Zeitaufwand nach §13 (Fr. 180.-/Stunde je angebrochene Viertelstunde), multipliziert mit Faktor 2 (§14' } },
